// ============================================================
// Content Creator — Approval Handler (FREE STACK)
// Imgur image hosting + Instagram Graph API + Threads API
// X/Twitter: manual post (official API = $100/mo, skipped)
// ============================================================
const fs = require('fs');
const input = $input.item.json;

const replyRaw = (input.Body || '').trim();
const replyCmd = replyRaw.toUpperCase().split('\n')[0].trim();
console.log('[APPROVAL] Received:', JSON.stringify(replyCmd));

// --- Load pending approvals ---
const pendingFilePath = 'D:\\categorized content\\scripts\\pending_approvals.json';
let pending = {};
try {
  pending = JSON.parse(fs.readFileSync(pendingFilePath, 'utf8'));
} catch(e) {
  return { action: 'error', error: 'Cannot read pending_approvals.json: ' + e.message };
}

const items         = Object.values(pending).sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
const awaitCaption  = items.find(i => i.status === 'awaiting_custom_caption');
const pendingItem   = awaitCaption || items.find(i => i.status === 'pending');

if (!pendingItem) return { action: 'none', message: 'No pending posts.' };

// --- Credentials ---
const TWILIO_SID      = process.env.TWILIO_ACCOUNT_SID       || $env.TWILIO_ACCOUNT_SID;
const TWILIO_TOKEN    = process.env.TWILIO_AUTH_TOKEN         || $env.TWILIO_AUTH_TOKEN;
const TWILIO_FROM     = process.env.TWILIO_WHATSAPP_FROM      || $env.TWILIO_WHATSAPP_FROM || 'whatsapp:+14155238886';
const TWILIO_TO       = process.env.TWILIO_WHATSAPP_TO        || $env.TWILIO_WHATSAPP_TO;
const IMGUR_CLIENT_ID = process.env.IMGUR_CLIENT_ID || $env.IMGUR_CLIENT_ID;

const IG_USER_ID      = process.env.INSTAGRAM_USER_ID         || $env.INSTAGRAM_USER_ID;
const IG_TOKEN        = process.env.INSTAGRAM_ACCESS_TOKEN    || $env.INSTAGRAM_ACCESS_TOKEN;
const TH_USER_ID      = process.env.THREADS_USER_ID           || $env.THREADS_USER_ID;
const TH_TOKEN        = process.env.THREADS_ACCESS_TOKEN      || $env.THREADS_ACCESS_TOKEN;

async function sendWhatsApp(msg) {
  const url   = 'https://api.twilio.com/2010-04-01/Accounts/' + TWILIO_SID + '/Messages.json';
  const creds = Buffer.from(TWILIO_SID + ':' + TWILIO_TOKEN).toString('base64');
  await fetch(url, {
    method:  'POST',
    headers: { 'Authorization': 'Basic ' + creds, 'Content-Type': 'application/x-www-form-urlencoded' },
    body:    new URLSearchParams({ From: TWILIO_FROM, To: TWILIO_TO, Body: msg }).toString(),
  });
}

function savePending() {
  fs.writeFileSync(pendingFilePath, JSON.stringify(pending, null, 2));
}

async function postContent(item, captionIndex, overrideCaption) {
  const chosenCaption = overrideCaption || item.captions[captionIndex];
  const results = { imgur: null, instagram: null, threads: null };

  // --- 1. Upload blurred image to Imgur (free public URL) ---
  const imgBuffer = fs.readFileSync(item.instagramPath);
  const b64       = imgBuffer.toString('base64');

  const imgurRes  = await fetch('https://api.imgur.com/3/image', {
    method:  'POST',
    headers: { 'Authorization': 'Client-ID ' + IMGUR_CLIENT_ID, 'Content-Type': 'application/json' },
    body:    JSON.stringify({ image: b64, type: 'base64' }),
  });
  const imgurData = await imgurRes.json();
  const publicUrl = imgurData?.data?.link;

  if (!publicUrl) {
    await sendWhatsApp('\u274c Cloudinary upload failed.\n' + JSON.stringify(cloudData).substring(0, 200));
    return;
  }
  results.imgur = publicUrl;
  console.log('[IMGUR] Public URL:', publicUrl);

  // --- 2. Post to Instagram Graph API (free) ---
  try {
    const igContRes = await fetch(
      'https://graph.facebook.com/v18.0/' + IG_USER_ID + '/media?' +
      new URLSearchParams({ image_url: publicUrl, caption: chosenCaption, access_token: IG_TOKEN }),
      { method: 'POST' }
    );
    const igCont = await igContRes.json();

    if (igCont.id) {
      const igPubRes = await fetch(
        'https://graph.facebook.com/v18.0/' + IG_USER_ID + '/media_publish?' +
        new URLSearchParams({ creation_id: igCont.id, access_token: IG_TOKEN }),
        { method: 'POST' }
      );
      const igPub = await igPubRes.json();
      results.instagram = igPub.id || null;
      console.log('[INSTAGRAM] Posted:', igPub.id);

      // Add hashtags as first comment
      const tags = (item.hashtags || []).join(' ');
      if (tags && igPub.id) {
        await fetch(
          'https://graph.facebook.com/v18.0/' + igPub.id + '/comments?' +
          new URLSearchParams({ message: tags, access_token: IG_TOKEN }),
          { method: 'POST' }
        );
      }
    } else {
      console.log('[INSTAGRAM] Error:', JSON.stringify(igCont));
    }
  } catch(e) { console.log('[INSTAGRAM] Caught:', e.message); }

  // --- 3. Post to Threads API (free) ---
  try {
    const thContRes = await fetch(
      'https://graph.threads.net/v1.0/' + TH_USER_ID + '/threads?' +
      new URLSearchParams({ media_type: 'IMAGE', image_url: publicUrl, text: chosenCaption, access_token: TH_TOKEN }),
      { method: 'POST' }
    );
    const thCont = await thContRes.json();

    if (thCont.id) {
      const thPubRes = await fetch(
        'https://graph.threads.net/v1.0/' + TH_USER_ID + '/threads_publish?' +
        new URLSearchParams({ creation_id: thCont.id, access_token: TH_TOKEN }),
        { method: 'POST' }
      );
      const thPub = await thPubRes.json();
      results.threads = thPub.id || null;
      console.log('[THREADS] Posted:', thPub.id);
    } else {
      console.log('[THREADS] Error:', JSON.stringify(thCont));
    }
  } catch(e) { console.log('[THREADS] Caught:', e.message); }

  // --- 4. Save state + confirm via WhatsApp ---
  item.status        = 'posted';
  item.postedAt      = new Date().toISOString();
  item.chosenCaption = chosenCaption;
  item.results       = results;
  pending[item.id]   = item;
  savePending();

  const igLine    = results.instagram ? '\u2705 Instagram' : '\u26a0\ufe0f Instagram — check n8n logs';
  const thLine    = results.threads   ? '\u2705 Threads'   : '\u26a0\ufe0f Threads — check n8n logs';
  const capLabel  = captionIndex >= 0 ? 'Caption ' + (captionIndex + 1) : 'Your caption';
  const preview   = chosenCaption.substring(0, 120) + (chosenCaption.length > 120 ? '...' : '');

  await sendWhatsApp(
    '\ud83d\udd25 Posted!\n' + igLine + '\n' + thLine + '\n\u270f\ufe0f X — copy & post manually\n\n' +
    capLabel + ':\n"' + preview + '"'
  );
}

// --- Custom caption flow ---
if (pendingItem.status === 'awaiting_custom_caption') {
  await postContent(pendingItem, -1, replyRaw);
  return { action: 'posted_custom', approvalId: pendingItem.id };
}

// --- Route standard commands ---
if (replyCmd === 'Y1') { await postContent(pendingItem, 0); return { action: 'posted', captionIndex: 0 }; }
if (replyCmd === 'Y2') { await postContent(pendingItem, 1); return { action: 'posted', captionIndex: 1 }; }
if (replyCmd === 'Y3') { await postContent(pendingItem, 2); return { action: 'posted', captionIndex: 2 }; }

if (replyCmd === 'N') {
  pendingItem.status = 'skipped';
  pending[pendingItem.id] = pendingItem;
  savePending();
  await sendWhatsApp('\u23ed\ufe0f Skipped: ' + pendingItem.fileName);
  return { action: 'skipped' };
}

if (replyCmd === 'E') {
  pendingItem.status = 'awaiting_custom_caption';
  pending[pendingItem.id] = pendingItem;
  savePending();
  await sendWhatsApp('\u270f\ufe0f Send your caption now and I\'ll post it.');
  return { action: 'awaiting_custom_caption' };
}

return { action: 'unknown', receivedReply: replyCmd, hint: 'Use Y1 / Y2 / Y3 / N / E' };
